import React, { useState, useEffect } from 'react';
import { getEventsByOrganiser, createEvent, updateEvent, deleteEvent, getAllLocations } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const EMPTY = { name: '', type: 'MOVIE', genres: [], address: '', duration: '', language: 'English', categoryName: '', status: 'ACTIVE' };
const TYPES     = ['MOVIE', 'CONCERT', 'EVENT'];
const ALL_GENRES = ['Action','Drama','Comedy','Romance','Horror','Thriller','Pop','Rock','Classical','Festival','Sports','Cultural','Other'];
const LANGUAGES = ['English','Tamil','Hindi','Telugu','Malayalam','Kannada','French','Japanese'];
const TYPE_COLOR = { MOVIE: 'var(--blue)', CONCERT: 'var(--gold)', EVENT: 'var(--green)' };

// Parse genre string → array
const parseGenres = (genreStr) => {
  if (!genreStr) return [];
  return genreStr.split(',').map((g) => g.trim()).filter(Boolean);
};

// Genre multi-select tag component
const GenrePicker = ({ selected, onChange }) => {
  return (
    <div>
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '7px' }}>
        {ALL_GENRES.map((g) => {
          const active = selected.includes(g);
          return (
            <button
              key={g}
              type="button"
              onClick={() => {
                if (active) onChange(selected.filter((x) => x !== g));
                else        onChange([...selected, g]);
              }}
              style={{
                padding: '5px 13px', borderRadius: '20px', border: '1.5px solid',
                fontSize: '12px', fontWeight: 600, cursor: 'pointer',
                fontFamily: 'var(--font-body)',
                transition: 'all 0.15s',
                borderColor: active ? 'var(--accent)' : 'var(--border)',
                background:  active ? 'var(--accent-dim)' : 'var(--bg-secondary)',
                color:       active ? 'var(--accent)' : 'var(--text-secondary)',
              }}
            >
              {active && <span style={{ marginRight: '4px' }}>✓</span>}
              {g}
            </button>
          );
        })}
      </div>
      {selected.length > 0 && (
        <div style={{ marginTop: '8px', fontSize: '12px', color: 'var(--text-muted)' }}>
          Selected: <span style={{ color: 'var(--accent)', fontWeight: 700 }}>{selected.join(', ')}</span>
        </div>
      )}
    </div>
  );
};

const AdminEventsPage = () => {
  const { user } = useAuth();
  const [events, setEvents]       = useState([]);
  const [locations, setLocations] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [modal, setModal]         = useState(false);
  const [form, setForm]           = useState(EMPTY);
  const [editId, setEditId]       = useState(null);
  const [saving, setSaving]       = useState(false);

  const load = async () => {
    try {
      const [evRes, locRes] = await Promise.all([
        getEventsByOrganiser(user.userId),
        getAllLocations(),
      ]);
      setEvents(Array.isArray(evRes.data?.data) ? evRes.data.data : []);
      setLocations(Array.isArray(locRes.data?.data) ? locRes.data.data : []);
    } catch { toast.error('Failed to load events'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const openCreate = () => { setForm(EMPTY); setEditId(null); setModal(true); };

  const openEdit = (e) => {
    setForm({
      name:         e.name         || '',
      type:         e.type         || 'MOVIE',
      genres:       parseGenres(e.genre),   // parse comma string → array
      address:      e.summary      || '',
      duration:     e.duration     || '',
      language:     e.language     || 'English',
      categoryName: e.categoryName || '',
      status:       e.status       || 'ACTIVE',
    });
    setEditId(e.eventId);
    setModal(true);
  };

  const handle = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const save = async () => {
    if (!form.name.trim()) { toast.error('Event name is required'); return; }
    setSaving(true);
    try {
      const payload = {
        ...form,
        genre:   form.genres.join(','),   // array → comma string for backend
        summary: form.address,
        organiserId: user.userId,
      };
      if (editId) { await updateEvent(editId, payload); toast.success('Event updated!'); }
      else        { await createEvent(payload);         toast.success('Event created!'); }
      setModal(false);
      load();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to save'); }
    finally { setSaving(false); }
  };

  const del = async (id) => {
    if (!window.confirm('Delete this event?')) return;
    try { await deleteEvent(id); toast.success('Event deleted'); load(); }
    catch (err) { toast.error(err.response?.data?.message || 'Delete failed'); }
  };

  return (
    <div className="container page-content" style={{ background: 'var(--bg-secondary)', minHeight: '100vh', paddingLeft: '28px', paddingRight: '28px' }}>

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 className="page-title">MY EVENTS</h1>
          <p className="page-subtitle">{events.length} events managed</p>
        </div>
        <button onClick={openCreate} className="btn btn-primary">➕ Create Event</button>
      </div>

      {loading ? (
        <div className="loading-center"><div className="spinner" /></div>
      ) : events.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">🎭</div>
          <h3>No Events Yet</h3>
          <p style={{ fontSize: '13px' }}>Create your first event to get started</p>
          <button onClick={openCreate} className="btn btn-primary" style={{ marginTop: '16px' }}>Create Event</button>
        </div>
      ) : (
        <div className="grid-3">
          {events.map((e) => {
            const genres = parseGenres(e.genre);
            return (
              <div key={e.eventId} className="card" style={{ padding: '20px', borderTop: `3px solid ${TYPE_COLOR[e.type] || 'var(--accent)'}` }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                  <span className={`badge ${e.status === 'ACTIVE' ? 'badge-success' : e.status === 'CANCELLED' ? 'badge-danger' : 'badge-muted'}`}>
                    {e.status}
                  </span>
                  <span style={{ fontSize: '12px', color: TYPE_COLOR[e.type], fontWeight: 600 }}>{e.type}</span>
                </div>

                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', marginBottom: '8px' }}>{e.name}</h3>

                {/* Multi-genre tags display */}
                {genres.length > 0 && (
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px', marginBottom: '6px' }}>
                    {genres.map((g) => (
                      <span key={g} style={{
                        fontSize: '10px', fontWeight: 700, padding: '2px 7px', borderRadius: '20px',
                        background: 'var(--bg-secondary)', border: '1px solid var(--border)',
                        color: 'var(--text-secondary)',
                      }}>{g}</span>
                    ))}
                  </div>
                )}

                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px' }}>
                  🌐 {e.language || '—'} &nbsp;·&nbsp; ⏱ {e.duration || '—'}
                </div>

                {e.summary && (
                  <p style={{ fontSize: '12px', color: 'var(--text-secondary)', lineHeight: 1.5, marginBottom: '14px', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
                    📍 {e.summary}
                  </p>
                )}

                <div style={{ display: 'flex', gap: '8px', paddingTop: '12px', borderTop: '1px solid var(--border)' }}>
                  <button onClick={() => openEdit(e)} className="btn btn-secondary btn-sm" style={{ flex: 1 }}>Edit</button>
                  <button onClick={() => del(e.eventId)} className="btn btn-danger btn-sm" style={{ flex: 1 }}>Delete</button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Modal */}
      {modal && (
        <div className="modal-overlay" onClick={() => setModal(false)}>
          <div className="modal" style={{ maxWidth: '580px' }} onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{editId ? 'EDIT EVENT' : 'CREATE EVENT'}</h3>
              <button className="modal-close" onClick={() => setModal(false)}>✕</button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>

              <div className="form-group" style={{ gridColumn: '1/-1' }}>
                <label className="form-label">Event Name *</label>
                <input className="form-input" value={form.name} onChange={(e) => handle('name', e.target.value)} placeholder="e.g. AR Rahman Live" />
              </div>

              <div className="form-group">
                <label className="form-label">Type</label>
                <select className="form-input" value={form.type} onChange={(e) => handle('type', e.target.value)}>
                  {TYPES.map((t) => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Status</label>
                <select className="form-input" value={form.status} onChange={(e) => handle('status', e.target.value)}>
                  {['ACTIVE', 'COMPLETED', 'CANCELLED'].map((s) => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Language</label>
                <select className="form-input" value={form.language} onChange={(e) => handle('language', e.target.value)}>
                  {LANGUAGES.map((l) => <option key={l} value={l}>{l}</option>)}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Duration</label>
                <input className="form-input" value={form.duration} onChange={(e) => handle('duration', e.target.value)} placeholder="2h 30min" />
              </div>

              <div className="form-group">
                <label className="form-label">Category</label>
                <input className="form-input" value={form.categoryName} onChange={(e) => handle('categoryName', e.target.value)} placeholder="e.g. Blockbuster" />
              </div>

              {/* Location dropdown — from DB */}
              <div className="form-group">
                <label className="form-label">Venue / Address</label>
                <select
                  className="form-input"
                  value={form.address}
                  onChange={(e) => handle('address', e.target.value)}
                >
                  <option value="">Select venue</option>
                  {locations.map((l) => (
                    <option key={l.locationId} value={l.locName}>
                      {l.locName}{l.address ? ` – ${l.address}` : ''}
                    </option>
                  ))}
                </select>
              </div>

              {/* Multi-genre picker */}
              <div className="form-group" style={{ gridColumn: '1/-1' }}>
                <label className="form-label">
                  Genre <span style={{ fontWeight: 400, color: 'var(--text-muted)', fontSize: '11px' }}>(select one or more)</span>
                </label>
                <GenrePicker
                  selected={form.genres}
                  onChange={(genres) => handle('genres', genres)}
                />
              </div>

            </div>

            <div style={{ display: 'flex', gap: '12px', marginTop: '16px' }}>
              <button onClick={() => setModal(false)} className="btn btn-secondary" style={{ flex: 1 }}>Cancel</button>
              <button onClick={save} disabled={saving} className="btn btn-primary" style={{ flex: 2 }}>
                {saving ? 'Saving...' : editId ? 'Update Event' : 'Create Event'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminEventsPage;
